import React, { useState, useRef } from 'react';
import { LANGUAGES } from '../constants';
import { analyzeSpeechAndTranslate } from '../services/geminiService';

const Dashboard: React.FC = () => {
  const [inputText, setInputText] = useState('');
  const [sourceLang, setSourceLang] = useState('en');
  const [targetLang, setTargetLang] = useState('es');
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [log, setLog] = useState<string[]>([]);

  const addLog = (msg: string) => setLog(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${msg}`]);

  const handleDub = async () => {
    if (!inputText) return;

    setIsProcessing(true);
    setResult(null);
    setLog([]);

    try {
      addLog('Initiating ASR module...');
      await new Promise(r => setTimeout(r, 800));

      addLog('Executing Variational Prosody Extraction...');
      await new Promise(r => setTimeout(r, 1000));

      addLog('Running Emotion Recognition model...');
      const analysis = await analyzeSpeechAndTranslate(inputText, LANGUAGES.find(l => l.code === targetLang)?.name || 'Spanish');

      addLog('Encoding latent style vector...');
      await new Promise(r => setTimeout(r, 800));

      addLog('Diffusion-based Speech Synthesis in progress...');
      await new Promise(r => setTimeout(r, 1200));

      addLog('Lip-Sync Alignment refining synchronization...');
      await new Promise(r => setTimeout(r, 1000));

      setResult(analysis);
      addLog('Dubbing process complete.');
    } catch (err) {
      addLog(`Error: ${err}`);
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 h-full">
      {/* Configuration & Input */}
