        </div>
      </div>

      {/* Real-time Results */}
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm h-full flex flex-col">
          <div className="flex items-center justify-between mb-8">
