          {result ? (
            <div className="flex-1 space-y-8 animate-fadeIn">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* Emotion Badge */}
                <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100">
