                  <div className="absolute -bottom-3 -right-3 w-12 h-12 bg-blue-600 rounded-full flex items-center justify-center shadow-lg shadow-blue-200 cursor-pointer hover:bg-blue-700 transition-colors">
                    <span className="text-white text-xl">▶️</span>
                  </div>
                </div>
              </div>

              {/* Visual Synchrony Status */}
              <div className="mt-auto pt-8 border-t border-slate-100">
                <div className="flex items-center justify-between mb-4">
                  <span className="text-xs font-bold text-slate-400 uppercase">Audio-Visual Synchrony Status</span>
                  <span className="text-xs text-blue-600 font-bold">Locked (0.84ms Jitter)</span>
                </div>
                <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                  <div className="bg-blue-500 h-full w-[94%]" />
                </div>
                <div className="mt-4 flex space-x-4">
                  <div className="flex-1 p-3 bg-slate-50 rounded-lg text-center">
                     <div className="text-[10px] text-slate-400 font-bold uppercase">Pitch Drift</div>
