  );
};

export default Dashboard;

import React, { useState } from 'react';
import { AppView } from './types';
import Layout from './components/Layout';
import Home from './components/Home';
import Dashboard from './components/Dashboard';
import Analysis from './components/Analysis';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.HOME);

  const renderView = () => {
    switch (currentView) {
      case AppView.HOME:
        return <Home onStart={() => setCurrentView(AppView.WORKSPACE)} />;
      case AppView.WORKSPACE:
        return <Dashboard />;
      case AppView.ANALYSIS:
        return <Analysis />;
      default:
        return <Home onStart={() => setCurrentView(AppView.WORKSPACE)} />;
    }
  };

  return (
    <Layout currentView={currentView} setView={setCurrentView}>
      {renderView()}
    </Layout>
  );
};

export default App;

import { GoogleGenAI, Type, Modality } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeSpeechAndTranslate = async (sourceText: string, targetLang: string) => {
  const prompt = `
    Analyze the following spoken text for its emotional tone and translate it into ${targetLang}.
    Provide the output in a structured format including:
    - Original Sentiment (Joy, Sadness, Anger, Neutral)
    - Confidence Score (0-1)
    - Translated Text
    - Prosody Instruction (Pitch, Rhythm, Intensity for a voice actor)

    Source Text: "${sourceText}"
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          emotion: { type: Type.STRING },
          confidence: { type: Type.NUMBER },
          translatedText: { type: Type.STRING },
          prosodyInstruction: { type: Type.STRING }
        },
        required: ["emotion", "confidence", "translatedText", "prosodyInstruction"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateExpressiveAudio = async (text: string, styleInstruction: string) => {
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Instruction: ${styleInstruction}. Text: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  return base64Audio;
};

export const generateCharacterVisual = async (emotion: string, language: string) => {
  const prompt = `A professional cinematic portrait of a character expressing ${emotion}, 
    themed with cultural elements from a ${language}-speaking region. Digital art style, 
    vibrant colors, expressive facial features, high quality.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: prompt }],
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

