  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [characterImage, setCharacterImage] = useState<string | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [log, setLog] = useState<string[]>([]);

  const addLog = (msg: string) => setLog(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${msg}`]);

  const decodeAndPlayAudio = async (base64: string) => {
    const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const binary = atob(base64);
    const len = binary.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binary.charCodeAt(i);
    }
    const dataInt16 = new Int16Array(bytes.buffer);
    const frameCount = dataInt16.length;
    const buffer = audioCtx.createBuffer(1, frameCount, 24000);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i] / 32768.0;
    }
    const source = audioCtx.createBufferSource();
    source.buffer = buffer;
    source.connect(audioCtx.destination);
    source.start();
  };

  const handleDub = async () => {
    if (!inputText) return;

    setIsProcessing(true);
    setResult(null);
    setCharacterImage(null);
    setAudioUrl(null);
    setLog([]);

    try {
      addLog('Module ASR: Extracting phonemes and duration markers...');
      await new Promise(r => setTimeout(r, 600));

      addLog('Module Emotion: Running sentiment inference on Gemini 3 Pro...');
      const targetLangName = LANGUAGES.find(l => l.code === targetLang)?.name || 'Spanish';
