      const visual = await generateCharacterVisual(analysis.emotion, targetLangName);
      setCharacterImage(visual);

      addLog('Module Synthesis: Generating 24kHz PCM audio with prosody injection...');
      const audioBase64 = await generateExpressiveAudio(analysis.translatedText, analysis.prosodyInstruction);
      if (audioBase64) {
        setAudioUrl(audioBase64);
      }

      addLog('Module Sync: Perfecting lip-alignment coefficients...');
      await new Promise(r => setTimeout(r, 800));

      addLog('Dubbing cycle finalized. Output ready.');
    } catch (err) {
      addLog(`Critial Pipeline Error: ${err}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const playResult = () => {
    if (audioUrl) {
      decodeAndPlayAudio(audioUrl);
    }
  };

  return (
