        </div>
      </div>

      {/* Main Preview Column */}
      <div className="lg:col-span-3 space-y-8">
        <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-sm h-full flex flex-col relative overflow-hidden">
