import { GoogleGenAI, Type, Modality } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * High-fidelity dubbing pipeline using Gemini 2.5 Native Audio capabilities.
 * It analyzes source audio/video for prosody, emotion, and identity.
 */
export const processDubbingPipeline = async (
  fileData: string, // base64
  mimeType: string,
  targetLang: string,
  instruction: string = ""
) => {
  // Pass 1: Semantic & Emotional Analysis
  // Use gemini-3-flash-preview for multi-modal analysis (Audio/Video support)
  const analysisResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          { inlineData: { data: fileData, mimeType } },
          { text: `Analyze the spoken content and emotion of this file for translation into ${targetLang}. 
                   Describe the speaker's vocal characteristics (pitch, tone, speed) and emotion in detail.` }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          sourceText: { type: Type.STRING },
          translatedText: { type: Type.STRING },
          emotion: { type: Type.STRING },
          prosodyData: { type: Type.STRING },
          confidence: { type: Type.NUMBER }
        },
        required: ["sourceText", "translatedText", "emotion", "prosodyData", "confidence"]
      }
    }
  });

  const metadata = JSON.parse(analysisResponse.text);

  // Pass 2: Voice-Preserving Synthesis
  // CRITICAL FIX: Use gemini-2.5-flash-native-audio-preview-12-2025 instead of TTS model.
  // This model supports multimodal input (Audio/Video) and can perform native voice-to-voice transfer.
  const synthesisResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    contents: [
      { 
        parts: [
          { inlineData: { data: fileData, mimeType } },
          { text: `TASK: Dub the provided audio/video into ${targetLang}. 
                   TEXT TO SPEAK: "${metadata.translatedText}"
                   INSTRUCTION: Maintain exactly the same voice identity, timbre, and emotion (${metadata.emotion}) as the original speaker. 
                   Ensure the speech rate and rhythm match the original timing for perfect synchronization.` }
        ] 
      }
    ],
    config: {
      responseModalities: [Modality.AUDIO],
    }
  });

  const dubbedAudioBase64 = synthesisResponse.candidates?.[0]?.content?.parts[0]?.inlineData?.data;

  return {
    metadata,
    dubbedAudioBase64
  };
};

export const generateCharacterVisual = async (emotion: string, language: string) => {
  const prompt = `A professional cinematic portrait of a character expressing ${emotion}, 
    themed with cultural elements from a ${language}-speaking region. Digital art style, 
    vibrant colors, expressive facial features, high quality.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: prompt }],
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

