const Dashboard: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [filePreviewUrl, setFilePreviewUrl] = useState<string | null>(null);
  const [targetLang, setTargetLang] = useState('es');
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [dubbedAudioUrl, setDubbedAudioUrl] = useState<string | null>(null);
  const [characterImage, setCharacterImage] = useState<string | null>(null);

  const [steps, setSteps] = useState<PipelineStep[]>([
    { id: 'asr', label: 'Voice Fingerprinting', status: 'pending', detail: 'Analyzing vocal timbre...' },
    { id: 'emo', label: 'Prosody Extraction', status: 'pending', detail: 'Mapping emotive contours...' },
    { id: 'trans', label: 'Contextual Translation', status: 'pending', detail: 'Applying target phonetics...' },
    { id: 'synth', label: 'Identity Synthesis', status: 'pending', detail: 'Reconstructing speaker voice...' },
    { id: 'sync', label: 'Lip-Sync Mastering', status: 'pending', detail: 'Matching frame trajectories...' },
  ]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoPreviewRef = useRef<HTMLVideoElement>(null);

  const updateStep = (id: string, status: PipelineStep['status'], detail?: string) => {
    setSteps(prev => prev.map(s => s.id === id ? { ...s, status, detail: detail || s.detail } : s));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      setFilePreviewUrl(URL.createObjectURL(selectedFile));
      setResult(null);
      setDubbedAudioUrl(null);
      setCharacterImage(null);
      setSteps(prev => prev.map(s => ({ ...s, status: 'pending' })));
    }
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result?.toString().split(',')[1] || '');
      reader.onerror = error => reject(error);
    });
  };

  const handleRunDubbing = async () => {
    if (!file) return;

    setIsProcessing(true);
    setResult(null);
    setDubbedAudioUrl(null);
    setCharacterImage(null);

    try {
      const base64 = await fileToBase64(file);
      const targetLangName = LANGUAGES.find(l => l.code === targetLang)?.name || 'Spanish';

      updateStep('asr', 'active', 'Extracting vocal identity vectors...');
      await new Promise(r => setTimeout(r, 1000));
      updateStep('asr', 'completed', 'Identity model loaded.');

      updateStep('emo', 'active', 'Analyzing emotive prosody...');
      await new Promise(r => setTimeout(r, 800));
      updateStep('emo', 'completed');

      updateStep('trans', 'active', 'Translating with semantic fidelity...');
      const { metadata, dubbedAudioBase64 } = await processDubbingPipeline(base64, file.type, targetLangName);
      setResult(metadata);
      updateStep('trans', 'completed');

      updateStep('synth', 'active', 'Synthesizing voice in ' + targetLangName + '...');
      if (dubbedAudioBase64) {
        setDubbedAudioUrl(dubbedAudioBase64);
      }

      generateCharacterVisual(metadata.emotion, targetLangName).then(setCharacterImage);

      await new Promise(r => setTimeout(r, 1500));
      updateStep('synth', 'completed', 'Vocal clone synchronized.');

      updateStep('sync', 'active', 'Mastering audio-visual alignment...');
      await new Promise(r => setTimeout(r, 1000));
      updateStep('sync', 'completed', 'Sync Lock: Optimal.');

    } catch (err) {
      console.error(err);
      setSteps(prev => prev.map(s => s.status === 'active' ? { ...s, status: 'error', detail: 'Pipeline Interrupted.' } : s));
    } finally {
      setIsProcessing(false);
    }
  };

  const playDubbed = async () => {
    if (!dubbedAudioUrl) return;

    // Start video playback if available
    if (videoPreviewRef.current) {
      videoPreviewRef.current.currentTime = 0;
      videoPreviewRef.current.play();
    }

    const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const binary = atob(dubbedAudioUrl);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
    const dataInt16 = new Int16Array(bytes.buffer);
    const buffer = audioCtx.createBuffer(1, dataInt16.length, 24000);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < dataInt16.length; i++) channelData[i] = dataInt16[i] / 32768.0;
    const source = audioCtx.createBufferSource();
    source.buffer = buffer;
    source.connect(audioCtx.destination);
    source.start();
  };

