            <span className="w-8 h-8 bg-blue-600 text-white rounded-xl flex items-center justify-center mr-3 text-xs">01</span>
            Source Dataset
          </h3>

          <div className="space-y-6 flex-1">
            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`border-4 border-dashed rounded-[2rem] p-8 text-center cursor-pointer transition-all hover:bg-slate-50 flex flex-col items-center justify-center min-h-[250px] ${file ? 'border-blue-200 bg-blue-50/30' : 'border-slate-100'}`}
            >
              <input type="file" ref={fileInputRef} onChange={handleFileChange} hidden accept="audio/*,video/*" />
              {file ? (
                <div className="space-y-4">
                  <div className="text-5xl">📼</div>
                  <div className="text-sm font-bold text-slate-700 truncate max-w-[200px]">{file.name}</div>
                  <div className="text-[10px] text-slate-400 font-mono uppercase">{(file.size / 1024 / 1024).toFixed(2)} MB</div>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="w-16 h-16 bg-slate-100 rounded-3xl flex items-center justify-center mx-auto text-3xl">📥</div>
                  <p className="text-sm text-slate-400 font-medium px-4">Upload Audio/Video for Identity Preservation</p>
                </div>
              )}
            </div>

            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Target Language</label>
              <select 
                value={targetLang}
                onChange={(e) => setTargetLang(e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 text-sm font-bold focus:ring-2 focus:ring-blue-500 appearance-none cursor-pointer"
              >
                {LANGUAGES.map(l => <option key={l.code} value={l.code}>{l.name}</option>)}
              </select>
            </div>
          </div>

          <button
            onClick={handleRunDubbing}
            disabled={!file || isProcessing}
            className={`w-full py-5 rounded-2xl mt-6 font-black text-xs uppercase tracking-widest transition-all shadow-xl ${!file || isProcessing ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-100 active:scale-95'}`}
          >
            {isProcessing ? 'Dubbing Engine Active...' : 'Execute Neural Dubbing'}
          </button>
        </div>
      </div>

      {/* CENTER & RIGHT: Output Terminals */}
      <div className="xl:col-span-3 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
