import { GoogleGenAI, Type, Modality } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * High-fidelity dubbing pipeline using Gemini models.
 * Fixes:
 * 1. 404 error: Uses 'gemini-3-flash-preview' for multimodal analysis as it's the most stable for generateContent.
 * 2. 400 error: Ensures 'gemini-2.5-flash-preview-tts' only receives text input, as it doesn't support image/video modalities.
 */
export const processDubbingPipeline = async (
  fileData: string, // base64
  mimeType: string,
  targetLang: string,
  instruction: string = ""
) => {
  // Pass 1: Semantic, Emotional, and Vocal Identity Analysis
  // 'gemini-3-flash-preview' handles multimodal (Audio/Video) input perfectly.
  const analysisResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          { inlineData: { data: fileData, mimeType } },
          { text: `Analyze this file for translation into ${targetLang}.
                   1. Transcribe the source text.
                   2. Translate it to ${targetLang}.
                   3. Identify the emotional tone (e.g., Joy, Anger, Sadness, Neutral).
                   4. Describe the speaker's vocal characteristics (Gender, Age, Pitch, Speed, Accent).
                   5. Provide instructions for a voice actor to dub this while maintaining the original's expressive style.` }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          sourceText: { type: Type.STRING },
          translatedText: { type: Type.STRING },
          emotion: { type: Type.STRING },
          vocalIdentity: { type: Type.STRING, description: "Description of gender, age, and timbre" },
          prosodyInstruction: { type: Type.STRING },
          confidence: { type: Type.NUMBER }
        },
        required: ["sourceText", "translatedText", "emotion", "vocalIdentity", "prosodyInstruction", "confidence"]
      }
    }
  });

  const metadata = JSON.parse(analysisResponse.text);

  // Logic to select a prebuilt voice that best matches the detected identity
  // This simulates "Voice Identity Preservation" within the SDK constraints
  let selectedVoice = 'Kore'; // Default
  const idLower = metadata.vocalIdentity.toLowerCase();
  if (idLower.includes('female') || idLower.includes('woman')) {
    selectedVoice = idLower.includes('high') ? 'Kore' : 'Aoede'; 
  } else if (idLower.includes('male') || idLower.includes('man')) {
    selectedVoice = idLower.includes('deep') ? 'Fenrir' : 'Puck';
  }

  // Pass 2: Expressive Audio Synthesis
  // CRITICAL: We only send TEXT to the TTS model to avoid "Image modality not enabled" error.
  const synthesisResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-preview-tts',
    contents: [
      { 
        parts: [
          { text: `Speak this in ${targetLang} with a ${metadata.emotion} tone. 
                   Style: ${metadata.prosodyInstruction}. 
                   Text to speak: "${metadata.translatedText}"` }
        ] 
      }
    ],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: selectedVoice }
        }
      }
    }
  });

  const dubbedAudioBase64 = synthesisResponse.candidates?.[0]?.content?.parts[0]?.inlineData?.data;

  return {
    metadata,
    dubbedAudioBase64
  };
};

export const generateCharacterVisual = async (emotion: string, language: string) => {
  const prompt = `A professional cinematic portrait of a character expressing ${emotion}, 
    themed with cultural elements from a ${language}-speaking region. Digital art style, 
    vibrant colors, expressive facial features, high quality.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: prompt }],
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

