  const [dubbedAudioUrl, setDubbedAudioUrl] = useState<string | null>(null);
  const [characterImage, setCharacterImage] = useState<string | null>(null);

  const [steps, setSteps] = useState<PipelineStep[]>([
    { id: 'asr', label: 'Identity Analysis', status: 'pending', detail: 'Extracting vocal fingerprints...' },
    { id: 'emo', label: 'Prosody Mapping', status: 'pending', detail: 'Decomposing emotional layers...' },
    { id: 'trans', label: 'Nuance Translation', status: 'pending', detail: 'Semantic cross-mapping...' },
    { id: 'synth', label: 'Vocal Reconstruction', status: 'pending', detail: 'Synthesizing cloned audio...' },
    { id: 'sync', label: 'AV Synchronization', status: 'pending', detail: 'Finalizing temporal alignment...' },
  ]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoPreviewRef = useRef<HTMLVideoElement>(null);

  const updateStep = (id: string, status: PipelineStep['status'], detail?: string) => {
    setSteps(prev => prev.map(s => s.id === id ? { ...s, status, detail: detail || s.detail } : s));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      setFilePreviewUrl(URL.createObjectURL(selectedFile));
      setResult(null);
      setDubbedAudioUrl(null);
      setCharacterImage(null);
      setSteps(prev => prev.map(s => ({ ...s, status: 'pending' })));
    }
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result?.toString().split(',')[1] || '');
      reader.onerror = error => reject(error);
    });
  };

  const handleRunDubbing = async () => {
    if (!file) return;

    setIsProcessing(true);
    setResult(null);
    setDubbedAudioUrl(null);
    setCharacterImage(null);

    try {
      const base64 = await fileToBase64(file);
      const targetLangName = LANGUAGES.find(l => l.code === targetLang)?.name || 'Spanish';

      updateStep('asr', 'active', 'Analyzing timbre and resonance...');
      await new Promise(r => setTimeout(r, 800));
      updateStep('asr', 'completed');

      updateStep('emo', 'active', 'Calculating emotional energy...');
      await new Promise(r => setTimeout(r, 600));
      updateStep('emo', 'completed');

      updateStep('trans', 'active', 'Generating dubbed semantic data...');
      const { metadata, dubbedAudioBase64 } = await processDubbingPipeline(base64, file.type, targetLangName);
      setResult(metadata);
      updateStep('trans', 'completed');

      updateStep('synth', 'active', 'Reconstructing voice profile...');
      if (dubbedAudioBase64) {
        setDubbedAudioUrl(dubbedAudioBase64);
      }

      generateCharacterVisual(metadata.emotion, targetLangName).then(setCharacterImage);

      await new Promise(r => setTimeout(r, 1200));
      updateStep('synth', 'completed', 'Identity preservation locked.');

      updateStep('sync', 'active', 'Executing frame-accurate lock...');
      await new Promise(r => setTimeout(r, 800));
      updateStep('sync', 'completed', 'Jitter < 4ms.');

    } catch (err: any) {
      console.error(err);
      const errMsg = err?.message || 'Pipeline Fault.';
      setSteps(prev => prev.map(s => s.status === 'active' ? { ...s, status: 'error', detail: errMsg } : s));
