            Project Config
          </h3>

          <div className="space-y-6 flex-1">
            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`border-4 border-dashed rounded-[2rem] p-8 text-center cursor-pointer transition-all hover:bg-slate-50 flex flex-col items-center justify-center min-h-[250px] ${file ? 'border-blue-200 bg-blue-50/30' : 'border-slate-100'}`}
