                  <div className="text-[10px] text-slate-400 font-mono uppercase">{(file.size / 1024 / 1024).toFixed(2)} MB</div>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="w-16 h-16 bg-slate-100 rounded-3xl flex items-center justify-center mx-auto text-3xl">📤</div>
                  <p className="text-sm text-slate-400 font-medium px-4 tracking-tight">Load Dataset for Voice Cloning</p>
                </div>
              )}
            </div>

            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Target Region</label>
              <select 
                value={targetLang}
                onChange={(e) => setTargetLang(e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 text-sm font-bold focus:ring-2 focus:ring-blue-500 appearance-none cursor-pointer"
              >
                {LANGUAGES.map(l => <option key={l.code} value={l.code}>{l.name}</option>)}
              </select>
            </div>
          </div>

          <button
            onClick={handleRunDubbing}
            disabled={!file || isProcessing}
            className={`w-full py-5 rounded-2xl mt-6 font-black text-xs uppercase tracking-widest transition-all shadow-xl ${!file || isProcessing ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white hover:bg-blue-700 active:scale-95'}`}
          >
            {isProcessing ? 'Processing...' : 'Run Neural Workflow'}
          </button>
        </div>
      </div>

      {/* Main Terminal Column */}
      <div className="xl:col-span-3 space-y-8">
