      console.error('Pipeline Error:', err);
      let errorMessage = 'Pipeline Interrupted.';

      // Handle 403 PERMISSION_DENIED and 404 Entity Not Found
      if (err?.status === 'PERMISSION_DENIED' || err?.message?.toLowerCase().includes('permission')) {
        errorMessage = '403: Key lacks permission. Use a paid project key.';
        setHasApiKey(false); // Alert user to re-select a valid key
      } else if (err?.message?.toLowerCase().includes('not found')) {
        errorMessage = '404: Resource or model not found.';
        setHasApiKey(false);
      }

      // Update steps to show error state
      setSteps(prev => prev.map(s => s.status === 'active' ? { ...s, status: 'error', detail: errorMessage } : s));
    } finally {
      setIsProcessing(false);
      setIsGeneratingVideo(false);
    }
  };

  const handleSyncPlayback = () => {
    if (outputVideoRef.current) {
      outputVideoRef.current.currentTime = 0;
      outputVideoRef.current.play();
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      {/* API Key Modal / Alert */}
      {!hasApiKey && (
        <div className="bg-gradient-to-r from-amber-50 to-orange-50 border border-amber-200 p-8 rounded-[2.5rem] flex flex-col md:flex-row items-center justify-between shadow-xl">
          <div className="flex items-center space-x-6 mb-6 md:mb-0">
            <div className="w-16 h-16 bg-amber-100 rounded-[1.5rem] flex items-center justify-center text-4xl shadow-inner">🔑</div>
            <div>
              <h4 className="font-black text-amber-900 text-lg uppercase tracking-tight">Advanced Feature Locked</h4>
