              className={`border-4 border-dashed rounded-[2rem] p-6 text-center cursor-pointer min-h-[180px] flex flex-col items-center justify-center transition-all ${file ? 'bg-blue-50 border-blue-200' : 'border-slate-100 hover:bg-slate-50 hover:border-slate-200'}`}
             >
