                {file && <span className="text-[8px] text-slate-400 font-mono mt-1">{(file.size / 1024 / 1024).toFixed(2)} MB</span>}
             </div>

             <div className="space-y-4">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Target Localization</label>
                <select 
                  value={targetLang} 
                  onChange={(e) => setTargetLang(e.target.value)} 
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold appearance-none cursor-pointer focus:ring-2 focus:ring-blue-500 outline-none"
                >
