             <button 
              onClick={runPipeline} 
              disabled={!file || isProcessing || !hasApiKey}
              className={`w-full py-5 rounded-2xl font-black text-xs uppercase tracking-widest transition-all ${!file || isProcessing || !hasApiKey ? 'bg-slate-100 text-slate-400 cursor-not-allowed' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-xl shadow-blue-100 active:scale-95'}`}
             >
                {isProcessing ? (
                  <div className="flex items-center justify-center space-x-2">
                    <div className="w-2 h-2 bg-white rounded-full animate-bounce"></div>
                    <div className="w-2 h-2 bg-white rounded-full animate-bounce" style={{animationDelay: '0.1s'}}></div>
                    <div className="w-2 h-2 bg-white rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
