                ) : 'Execute Pipeline'}
             </button>
          </div>

          {/* Trace Log */}
          <div className="bg-slate-900 p-6 rounded-[2.5rem] border border-slate-800 shadow-2xl">
             <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6 flex items-center">
                <span className="w-2 h-2 bg-blue-500 rounded-full mr-2"></span>
                Inference Trace
             </h4>
             <div className="space-y-5">
                {steps.map(step => (
                  <div key={step.id} className="flex space-x-3 items-start">
                     <div className={`w-5 h-5 rounded-md flex items-center justify-center text-[8px] font-bold border transition-colors ${step.status === 'completed' ? 'bg-green-500 border-green-400' : step.status === 'active' ? 'bg-blue-500 border-blue-400 animate-pulse' : step.status === 'error' ? 'bg-red-500 border-red-400' : 'bg-slate-800 border-slate-700 text-slate-500'}`}>
                        {step.status === 'completed' ? '✓' : step.status === 'error' ? '!' : ''}
                     </div>
                     <div className="flex-1">
                        <div className={`text-[11px] font-bold ${step.status === 'pending' ? 'text-slate-700' : 'text-slate-300'}`}>{step.label}</div>
                        <div className={`text-[9px] font-mono mt-0.5 truncate ${step.status === 'error' ? 'text-red-400' : 'text-slate-600'}`}>{step.detail}</div>
                     </div>
                  </div>
                ))}
             </div>
          </div>
        </div>

        {/* Right Preview Panel */}
        <div className="lg:col-span-3 space-y-8">
           <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {/* Source Monitor */}
              <div className="bg-black rounded-[3rem] overflow-hidden aspect-video relative group shadow-2xl border border-slate-200">
                 <video ref={sourceVideoRef} src={filePreviewUrl || ''} className="w-full h-full object-cover opacity-80" muted playsInline />
                 <div className="absolute top-6 left-6 px-3 py-1 bg-white/10 backdrop-blur rounded-full text-[10px] font-black text-white uppercase tracking-widest border border-white/20">Input Stream</div>
                 {!file && (
                    <div className="absolute inset-0 flex items-center justify-center opacity-10">
                       <span className="text-9xl text-white">🎞️</span>
                    </div>
                 )}
              </div>

              {/* AI Dub Monitor */}
              <div className="bg-slate-900 rounded-[3rem] overflow-hidden aspect-video relative shadow-2xl border border-slate-800 group">
                 {videoResultUrl ? (
