                             <div className="text-7xl">🧬</div>
                             <h4 className="text-white font-black uppercase text-[10px] tracking-widest">Awaiting Resynthesis</h4>
                          </div>
                       )}
                    </div>
                 )}
                 <div className="absolute top-6 right-6 px-3 py-1 bg-blue-600 rounded-full text-[10px] font-black text-white uppercase tracking-widest border border-blue-400">Master Output</div>
              </div>
           </div>

           {/* Transcript & Metadata Card */}
           <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-xl space-y-10 relative overflow-hidden">
              <div className="absolute top-0 right-0 p-8 opacity-5 text-9xl font-black pointer-events-none">SYB</div>
              {metadata ? (
                 <div className="animate-fadeIn space-y-8 relative z-10">
                    <div className="flex flex-col md:flex-row md:items-center justify-between pb-8 border-b border-slate-100 gap-4">
                       <div>
                          <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Identity Clone Record</h2>
                          <p className="text-sm text-slate-400 font-medium">{metadata.vocalIdentity}</p>
                       </div>
                       <button 
                        onClick={handleSyncPlayback} 
                        className="px-8 py-3 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all shadow-xl shadow-slate-200 active:scale-95"
                       >
                         Trigger Master Playback
                       </button>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
                       <div className="md:col-span-2 space-y-6">
                          <div>
                             <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-3 block">Neural Translation Output</label>
                             <div className="p-8 bg-slate-50 rounded-[2.5rem] border border-slate-100 italic text-2xl text-slate-700 leading-relaxed font-serif shadow-inner">
                                "{metadata.translatedText}"
                             </div>
                          </div>
                          <div className="grid grid-cols-2 gap-4">
                             <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                                <span className="text-[8px] font-black text-slate-400 uppercase block mb-1">Emotion State</span>
                                <span className="text-xs font-black text-blue-600 uppercase tracking-tight">{metadata.emotion}</span>
                             </div>
                             <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                                <span className="text-[8px] font-black text-slate-400 uppercase block mb-1">Confidence Score</span>
                                <span className="text-xs font-black text-green-600 uppercase tracking-tight">{(metadata.confidence * 100).toFixed(1)}%</span>
                             </div>
                          </div>
                       </div>

                       <div className="space-y-6">
                          <div className="bg-blue-600 p-8 rounded-[2.5rem] text-white shadow-2xl shadow-blue-100 relative overflow-hidden">
                             <div className="absolute -bottom-4 -right-4 text-6xl opacity-20">📡</div>
                             <h4 className="text-[9px] font-black text-blue-200 uppercase tracking-widest mb-6">Prosodic Protocol</h4>
                             <div className="flex items-center space-x-4 mb-6">
                                <div className="w-12 h-12 bg-white/20 rounded-2xl flex items-center justify-center text-xl shadow-inner">🗣️</div>
                                <div className="text-[11px] font-black leading-tight uppercase tracking-tight">Active Vocal Clone</div>
                             </div>
                             <p className="text-[10px] text-blue-100 leading-relaxed font-medium">
                                {metadata.prosodyInstruction}
                             </p>
                          </div>
                          <div className="p-6 bg-slate-50 rounded-[2rem] border border-slate-100">
                             <div className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-2">Original Context</div>
                             <p className="text-[11px] text-slate-500 italic leading-snug">"{metadata.sourceText}"</p>
