import { GoogleGenAI, Type, Modality } from "@google/genai";

/**
 * Stage 1 & 2: Multimodal Analysis and Audio Synthesis.
 * This function analyzes source media and synthesizes dubbed audio.
 */
export const processDubbingPipeline = async (
  fileData: string, // base64
  mimeType: string,
  targetLang: string
) => {
  // Fresh instance to ensure we use the latest injected API Key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // 1. Multimodal Analysis (Voice + Emotion + Script)
  const analysisResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          { inlineData: { data: fileData, mimeType } },
          { text: `Analyze this file for high-fidelity dubbing into ${targetLang}. 
                   Output JSON only. Include: 
                   sourceText (original transcription), 
                   translatedText (natural translation), 
                   emotion (detected emotive state), 
                   vocalIdentity (gender, age, and timbre description), 
                   prosodyInstruction (how to speak the translated text to match the original energy), 
                   and confidence (0-1).` }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          sourceText: { type: Type.STRING },
          translatedText: { type: Type.STRING },
          emotion: { type: Type.STRING },
          vocalIdentity: { type: Type.STRING },
          prosodyInstruction: { type: Type.STRING },
          confidence: { type: Type.NUMBER }
        },
        required: ["sourceText", "translatedText", "emotion", "vocalIdentity", "prosodyInstruction", "confidence"]
      }
    }
  });

  const metadata = JSON.parse(analysisResponse.text);

  // 2. Audio Synthesis mimicking identity using TTS model
  const synthesisResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-preview-tts',
    contents: [
      { 
        parts: [
          { text: `TASK: Act as a professional dubbing artist. 
                   EMOTION: ${metadata.emotion}. 
                   STYLE: ${metadata.vocalIdentity}. ${metadata.prosodyInstruction}. 
                   TARGET LANGUAGE: ${targetLang}. 
                   PHRASE: "${metadata.translatedText}"` }
        ] 
      }
    ],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { 
            voiceName: metadata.vocalIdentity.toLowerCase().includes('female') ? 'Kore' : 'Fenrir' 
          }
        }
      }
    }
  });

  const dubbedAudioBase64 = synthesisResponse.candidates?.[0]?.content?.parts[0]?.inlineData?.data;

  return { metadata, dubbedAudioBase64 };
};

/**
 * Stage 3: Generative Lip-Sync Video Resynthesis using Veo.
 */
export const generateDubbedVideo = async (
  firstFrameBase64: string,
  translatedText: string,
  emotion: string,
  targetLang: string
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `A cinematic video of the person in the reference image 
    speaking in ${targetLang}. Mouth movements match the phrase: "${translatedText}". 
    Expression: ${emotion}. 
    Keep the background and lighting consistent.`;

  try {
    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt,
      image: {
        imageBytes: firstFrameBase64,
        mimeType: 'image/png',
      },
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: '16:9'
      }
    });
    return operation;
  } catch (e: any) {
    // Surface the 403 error specifically for the caller
    if (e?.status === 'PERMISSION_DENIED' || e?.code === 403) {
      throw { status: 'PERMISSION_DENIED', message: 'The provided API key lacks Veo generation permissions.' };
    }
    throw e;
  }
};

/**
 * Polls the status of a video generation operation.
 */
export const pollOperation = async (operation: any) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return await ai.operations.getVideosOperation({ operation });
};

