/**
 * Stage 4: Comparative Fidelity Analysis (Algorithm-based worthiness)
 */
export const runComparativeAnalysis = async (
  sourceMetadata: any,
  dubbedAudioBase64: string,
  targetLang: string
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const analysisPrompt = `Compare the source media and the synthesized dubbing result. 
    Calculate a "Worthiness Score" (0-100) based on:
    1. Vocal Identity Retention (Timbre matching)
    2. Prosodic Fidelity (Emotional energy curve preservation)
    3. Linguistic Accuracy (Translation naturalness)
    4. ROI (Effort vs Quality gain for the user)

    Source Context: "${sourceMetadata.sourceText}" (${sourceMetadata.emotion})
    Output Goal: "${sourceMetadata.translatedText}" in ${targetLang}

    Output JSON with scores for: identityMatch, prosodySync, linguisticFlow, worthinessScore, and a "comparisonSummary" string.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          { text: analysisPrompt },
          { inlineData: { data: dubbedAudioBase64, mimeType: 'audio/pcm' } }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          identityMatch: { type: Type.NUMBER },
          prosodySync: { type: Type.NUMBER },
          linguisticFlow: { type: Type.NUMBER },
          worthinessScore: { type: Type.NUMBER },
          comparisonSummary: { type: Type.STRING }
        },
        required: ["identityMatch", "prosodySync", "linguisticFlow", "worthinessScore", "comparisonSummary"]
      }
    }
  });

  return JSON.parse(response.text);
};

