      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt,
      image: {
        imageBytes: firstFrameBase64,
        mimeType: 'image/png',
      },
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: '16:9'
      }
    });
    return operation;
  } catch (e: any) {
    console.error("Veo Error:", e);
    throw e;
  }
};

