        setFidelityReport(report);
        updateStep('analysis', 'completed', `Worthiness: ${report.worthinessScore}%`);
      }

    } catch (err: any) {
      console.error(err);
      setSteps(prev => prev.map(s => s.status === 'active' ? { ...s, status: 'error', detail: 'Engine Error (500/Timeout)' } : s));
    } finally {
      setIsProcessing(false);
    }
  };

