                <select value={targetLang} onChange={(e) => setTargetLang(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold appearance-none outline-none focus:ring-2 focus:ring-blue-500">
                  {LANGUAGES.map(l => <option key={l.code} value={l.code}>{l.name}</option>)}
                </select>
             </div>
             <button onClick={runPipeline} disabled={!file || isProcessing} className={`w-full py-5 rounded-2xl font-black text-xs uppercase tracking-widest transition-all ${!file || isProcessing ? 'bg-slate-100 text-slate-400 cursor-not-allowed' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-xl shadow-blue-100 active:scale-95'}`}>
                {isProcessing ? 'Processing Engine...' : 'Generate AI Dub'}
             </button>
          </div>

          <div className="bg-slate-900 p-6 rounded-[2.5rem] border border-slate-800 shadow-2xl">
             <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6">Pipeline Trace</h4>
             <div className="space-y-5">
                {steps.map(step => (
                  <div key={step.id} className="flex space-x-3 items-start">
                     <div className={`w-5 h-5 rounded-md flex items-center justify-center text-[8px] font-bold border transition-colors ${step.status === 'completed' ? 'bg-green-500 border-green-400 text-white' : step.status === 'active' ? 'bg-blue-500 border-blue-400 animate-pulse text-white' : step.status === 'error' ? 'bg-red-500 border-red-400 text-white' : 'bg-slate-800 border-slate-700 text-slate-500'}`}>
                        {step.status === 'completed' ? '✓' : ''}
                     </div>
                     <div className="flex-1">
                        <div className={`text-[11px] font-bold ${step.status === 'pending' ? 'text-slate-700' : 'text-slate-300'}`}>{step.label}</div>
                        <div className="text-[9px] text-slate-600 font-mono mt-0.5 truncate">{step.detail}</div>
                     </div>
                  </div>
                ))}
             </div>
          </div>
        </div>

        <div className="lg:col-span-3 space-y-8">
           <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="bg-black rounded-[3rem] overflow-hidden aspect-video relative shadow-2xl">
