import React, { useState, useRef, useEffect } from 'react';
import { LANGUAGES } from '../constants';
import { processDubbingPipeline, generateDubbedVideo, pollOperation, runComparativeAnalysis } from '../services/geminiService';
import { PipelineStep, DubbingMetadata } from '../types';

/**
 * Utility to wrap raw PCM data in a standard WAV header
 */
const createWavFile = (base64Pcm: string, sampleRate = 24000) => {
  const pcmData = atob(base64Pcm);
  const dataSize = pcmData.length;
  const buffer = new ArrayBuffer(44 + dataSize);
  const view = new DataView(buffer);

  const writeString = (offset: number, string: string) => {
    for (let i = 0; i < string.length; i++) {
      view.setUint8(offset + i, string.charCodeAt(i));
    }
  };

  writeString(0, 'RIFF');
  view.setUint32(4, 36 + dataSize, true);
  writeString(8, 'WAVE');
  writeString(12, 'fmt ');
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true);
  view.setUint16(22, 1, true);
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, sampleRate * 2, true);
  view.setUint16(32, 2, true);
  view.setUint16(34, 16, true);
  writeString(36, 'data');
  view.setUint32(40, dataSize, true);

  const uint8View = new Uint8Array(buffer, 44);
  for (let i = 0; i < dataSize; i++) {
    uint8View[i] = pcmData.charCodeAt(i);
  }

  return new Blob([buffer], { type: 'audio/wav' });
};

const Dashboard: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [filePreviewUrl, setFilePreviewUrl] = useState<string | null>(null);
  const [targetLang, setTargetLang] = useState('es');

  const [isProcessing, setIsProcessing] = useState(false);
  const [isGeneratingVideo, setIsGeneratingVideo] = useState(false);
  const [hasApiKey, setHasApiKey] = useState<boolean | null>(null);

  const [metadata, setMetadata] = useState<DubbingMetadata | null>(null);
  const [dubbedAudioBase64, setDubbedAudioBase64] = useState<string | null>(null);
  const [videoResultUrl, setVideoResultUrl] = useState<string | null>(null);
  const [fidelityReport, setFidelityReport] = useState<any>(null);

  const [steps, setSteps] = useState<PipelineStep[]>([
    { id: 'asr', label: 'Vocal Fingerprinting', status: 'pending', detail: 'Analyzing speaker identity...' },
    { id: 'trans', label: 'Semantic Dubbing', status: 'pending', detail: 'Translating with prosody...' },
    { id: 'synth', label: 'Audio Resynthesis', status: 'pending', detail: 'Cloning vocal characteristics...' },
    { id: 'veo', label: 'Lip-Sync Generation', status: 'pending', detail: 'Synthesizing visual frames...' },
    { id: 'analysis', label: 'Worthiness Analysis', status: 'pending', detail: 'Evaluating algorithm fidelity...' },
  ]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const sourceVideoRef = useRef<HTMLVideoElement>(null);
  const outputVideoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    const checkKey = async () => {
      try {
        const selected = await (window as any).aistudio?.hasSelectedApiKey();
        setHasApiKey(!!selected);
      } catch (e) {
        setHasApiKey(false);
      }
    };
    checkKey();
  }, []);

  const handleOpenKeySelector = async () => {
    try {
      await (window as any).aistudio?.openSelectKey();
      setHasApiKey(true);
    } catch (e) {
      console.error("Failed to open key selector", e);
    }
  };

  const updateStep = (id: string, status: PipelineStep['status'], detail?: string) => {
    setSteps(prev => prev.map(s => s.id === id ? { ...s, status, detail: detail || s.detail } : s));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      setFilePreviewUrl(URL.createObjectURL(selectedFile));
      setMetadata(null);
      setFidelityReport(null);
      setVideoResultUrl(null);
      setDubbedAudioBase64(null);
      setSteps(prev => prev.map(s => ({ ...s, status: 'pending', detail: '' })));
    }
  };

  const handleDownloadStem = () => {
    if (!dubbedAudioBase64) return;
    const wavBlob = createWavFile(dubbedAudioBase64);
    const link = document.createElement('a');
    link.href = URL.createObjectURL(wavBlob);
    link.download = `emo_dub_stem_${targetLang}.wav`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleDownloadMaster = () => {
    if (!videoResultUrl) return;
    const link = document.createElement('a');
    link.href = videoResultUrl;
    link.download = `emo_dub_master_${targetLang}.mp4`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const runPipeline = async () => {
    if (!file) return;
    setIsProcessing(true);
    setFidelityReport(null);
    setMetadata(null);
    setVideoResultUrl(null);
    setDubbedAudioBase64(null);

    setSteps(prev => prev.map(s => ({ ...s, status: 'pending', detail: '' })));

    try {
      const base64 = await new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => resolve(reader.result?.toString().split(',')[1] || '');
      });
      const langName = LANGUAGES.find(l => l.code === targetLang)?.name || 'Spanish';

      updateStep('asr', 'active');
      const { metadata: meta, dubbedAudioBase64: audioData } = await processDubbingPipeline(base64, file.type, langName);
      setMetadata(meta);
      if (audioData) setDubbedAudioBase64(audioData);
      updateStep('asr', 'completed');
      updateStep('trans', 'completed');
      updateStep('synth', 'completed');

      if (file.type.startsWith('video')) {
        setIsGeneratingVideo(true);
        updateStep('veo', 'active');

        const canvas = document.createElement('canvas');
        canvas.width = sourceVideoRef.current?.videoWidth || 640;
        canvas.height = sourceVideoRef.current?.videoHeight || 360;
        const ctx = canvas.getContext('2d');
        if (ctx) ctx.drawImage(sourceVideoRef.current!, 0, 0);
        const frame = canvas.toDataURL('image/png').split(',')[1];

        try {
          let operation = await generateDubbedVideo(frame, meta.translatedText, meta.emotion, langName);
          while (!operation.done) {
            await new Promise(r => setTimeout(r, 10000));
            operation = await pollOperation(operation);
          }
          const link = operation.response?.generatedVideos?.[0]?.video?.uri;
          if (link) {
            const res = await fetch(`${link}&key=${process.env.API_KEY}`);
            setVideoResultUrl(URL.createObjectURL(await res.blob()));
            updateStep('veo', 'completed');
          }
        } catch (e: any) {
          console.error("Veo Error:", e);
          updateStep('veo', 'error', 'Resource limits or auth failure.');
        } finally {
          setIsGeneratingVideo(false);
        }
      }

      updateStep('analysis', 'active');
      if (audioData) {
        const report = await runComparativeAnalysis(meta, audioData, langName);
        setFidelityReport(report);
        updateStep('analysis', 'completed', `Worthiness: ${report.worthinessScore}%`);
      }

    } catch (err: any) {
      console.error(err);
      setSteps(prev => prev.map(s => s.status === 'active' ? { ...s, status: 'error', detail: 'Engine Error' } : s));
    } finally {
      setIsProcessing(false);
    }
  };

  if (hasApiKey === false) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[50vh] text-center p-8 bg-white rounded-[3rem] border border-slate-200 shadow-xl">
        <div className="text-6xl mb-6">🔑</div>
        <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight mb-4">Paid API Key Required</h2>
        <p className="text-slate-500 max-w-md mb-8 font-medium">
          Veo video generation requires a paid API key. Please select a project with billing enabled to unlock the full dubbing pipeline.
        </p>
        <button 
          onClick={handleOpenKeySelector}
          className="px-10 py-5 bg-blue-600 hover:bg-blue-700 text-white font-black rounded-2xl transition-all shadow-xl shadow-blue-100 uppercase text-xs tracking-widest active:scale-95"
        >
          Select Paid API Key
        </button>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 md:gap-8 animate-fadeIn">
      {/* Sidebar Controls */}
      <div className="lg:col-span-1 space-y-6">
        <div className="bg-white p-6 rounded-[2rem] md:rounded-[2.5rem] border border-slate-200 shadow-sm space-y-6">
           <h3 className="text-lg font-black text-slate-800 uppercase tracking-tighter">Dubbing Studio</h3>
           <div 
             onClick={() => fileInputRef.current?.click()} 
             className={`border-4 border-dashed rounded-[1.5rem] p-6 text-center cursor-pointer min-h-[140px] flex flex-col items-center justify-center transition-all ${file ? 'bg-blue-50 border-blue-200' : 'border-slate-100 hover:bg-slate-50'}`}
           >
              <input type="file" ref={fileInputRef} onChange={handleFileChange} hidden accept="video/*,audio/*" />
              <span className="text-3xl mb-2">{file ? '🎞️' : '📤'}</span>
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest break-all">
                {file ? file.name : 'Upload Source Media'}
              </p>
           </div>

           <div className="space-y-4">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Target Language</label>
              <select 
                value={targetLang} 
                onChange={(e) => setTargetLang(e.target.value)} 
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold appearance-none outline-none focus:ring-2 focus:ring-blue-500"
              >
                {LANGUAGES.map(l => <option key={l.code} value={l.code}>{l.name}</option>)}
              </select>
           </div>

           <button 
             onClick={runPipeline} 
             disabled={!file || isProcessing} 
             className={`w-full py-5 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${!file || isProcessing ? 'bg-slate-100 text-slate-400 cursor-not-allowed' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-lg shadow-blue-100 active:scale-95'}`}
           >
              {isProcessing ? 'Synthesizing...' : 'Run Pipeline'}
           </button>
        </div>

        <div className="bg-slate-900 p-6 rounded-[2rem] border border-slate-800 shadow-xl overflow-hidden">
           <h4 className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-6">Execution Log</h4>
           <div className="space-y-4">
              {steps.map(step => (
                <div key={step.id} className="flex space-x-3 items-start">
                   <div className={`w-4 h-4 mt-0.5 rounded flex items-center justify-center text-[7px] font-bold border shrink-0 transition-colors ${step.status === 'completed' ? 'bg-green-500 border-green-400 text-white' : step.status === 'active' ? 'bg-blue-500 border-blue-400 animate-pulse text-white' : step.status === 'error' ? 'bg-red-500 border-red-400 text-white' : 'bg-slate-800 border-slate-700 text-slate-500'}`}>
                      {step.status === 'completed' ? '✓' : ''}
                   </div>
                   <div className="flex-1 min-w-0">
                      <div className={`text-[10px] font-bold truncate ${step.status === 'pending' ? 'text-slate-700' : 'text-slate-300'}`}>{step.label}</div>
                      <div className="text-[8px] text-slate-600 font-mono mt-0.5 break-words line-clamp-2">{step.detail}</div>
                   </div>
                </div>
              ))}
           </div>
        </div>
      </div>

      {/* Main Workspace */}
      <div className="lg:col-span-3 space-y-6 md:space-y-8">
         <div className="grid grid-cols-1 md:grid-cols-2 gap-6 md:gap-8">
            <div className="bg-black rounded-[2rem] md:rounded-[3rem] overflow-hidden aspect-video relative shadow-2xl">
               <video ref={sourceVideoRef} src={filePreviewUrl || ''} className="w-full h-full object-cover opacity-80" muted playsInline />
               <div className="absolute top-4 left-4 px-3 py-1 bg-white/10 backdrop-blur rounded-full text-[9px] font-black text-white uppercase tracking-widest border border-white/20">Source Feed</div>
            </div>
            <div className="bg-slate-900 rounded-[2rem] md:rounded-[3rem] overflow-hidden aspect-video relative shadow-2xl border border-slate-800">
               {videoResultUrl ? (
                  <video ref={outputVideoRef} src={videoResultUrl} className="w-full h-full object-cover" controls />
               ) : (
                  <div className="w-full h-full flex flex-col items-center justify-center text-center p-8">
                     {isGeneratingVideo ? (
                        <div className="space-y-4">
                           <div className="w-12 h-12 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto"></div>
                           <h4 className="text-white font-black uppercase text-[9px] tracking-widest animate-pulse">Veo Synthesizing Video...</h4>
                        </div>
                     ) : (
                        <div className="opacity-20 space-y-3">
                           <div className="text-5xl">🧪</div>
                           <h4 className="text-white font-black uppercase text-[9px] tracking-widest">Awaiting Dubbing Results</h4>
                        </div>
                     )}
                  </div>
               )}
               <div className="absolute top-4 right-4 px-3 py-1 bg-blue-600 rounded-full text-[9px] font-black text-white uppercase tracking-widest">Master Result</div>
            </div>
         </div>

         {fidelityReport && (
            <div className="bg-gradient-to-br from-blue-600 to-indigo-700 p-8 md:p-10 rounded-[2.5rem] md:rounded-[3.5rem] text-white shadow-xl animate-fadeIn relative overflow-hidden">
               <div className="relative z-10 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6">
                  <div className="flex-1 min-w-0">
                     <h3 className="text-2xl md:text-3xl font-black tracking-tighter mb-2 italic">Identity Fidelity Match</h3>
                     <p className="text-blue-100 text-xs md:text-sm font-medium leading-relaxed break-words">
                        {fidelityReport.comparisonSummary}
                     </p>
                  </div>
                  <div className="bg-white/10 backdrop-blur-xl p-6 md:p-8 rounded-[2rem] border border-white/20 text-center shrink-0 min-w-[140px]">
                     <div className="text-[8px] font-black text-blue-200 uppercase tracking-widest mb-1">Quality Score</div>
                     <div className="text-4xl md:text-6xl font-black tracking-tighter">{fidelityReport.worthinessScore}%</div>
                  </div>
               </div>
            </div>
         )}

         <div className="bg-white p-6 md:p-10 rounded-[2rem] md:rounded-[3rem] border border-slate-200 shadow-sm space-y-8">
            {metadata ? (
               <div className="animate-fadeIn space-y-8">
                  <div className="flex flex-col md:flex-row justify-between items-start md:items-center pb-6 border-b border-slate-100 gap-6">
                     <div className="min-w-0">
                        <h2 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tighter truncate">Synthesis Report</h2>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Engine: Gemini-2.5-Flash-TTS</p>
                     </div>
                     <div className="flex flex-wrap gap-3 w-full md:w-auto">
                        <button 
                          onClick={handleDownloadStem}
                          disabled={!dubbedAudioBase64}
                          className="flex-1 md:flex-none px-5 py-3 bg-slate-100 hover:bg-slate-200 text-slate-600 font-black text-[9px] uppercase tracking-widest rounded-xl transition-all active:scale-95 disabled:opacity-50"
                        >
                          Audio Stem
                        </button>
                        <button 
                          onClick={handleDownloadMaster}
                          disabled={!videoResultUrl}
                          className="flex-1 md:flex-none px-5 py-3 bg-blue-600 hover:bg-blue-700 text-white font-black text-[9px] uppercase tracking-widest rounded-xl transition-all shadow-lg shadow-blue-100 active:scale-95 disabled:opacity-50"
                        >
                          Master Video
                        </button>
                     </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8 lg:gap-12">
                     <div className="space-y-4">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Translated Phonemes</label>
                        <div className="p-6 md:p-8 bg-slate-50 rounded-[2rem] border border-slate-100 italic text-xl md:text-2xl text-slate-700 leading-relaxed font-serif shadow-inner relative overflow-hidden break-words">
                           "{metadata.translatedText}"
                        </div>
                     </div>
                     <div className="grid grid-cols-2 gap-4 h-fit">
                        <div className="p-4 md:p-6 bg-slate-50 rounded-[1.5rem] border border-slate-100 text-center">
                           <div className="text-[7px] font-black text-slate-400 uppercase tracking-widest mb-2">Emotion</div>
                           <div className="text-xl font-black text-blue-600 truncate">{metadata.emotion}</div>
                        </div>
                        <div className="p-4 md:p-6 bg-slate-50 rounded-[1.5rem] border border-slate-100 text-center">
                           <div className="text-[7px] font-black text-slate-400 uppercase tracking-widest mb-2">Confidence</div>
                           <div className="text-xl font-black text-indigo-600">{(metadata.confidence * 100).toFixed(0)}%</div>
                        </div>
                        <div className="col-span-2 p-4 md:p-6 bg-slate-50 rounded-[1.5rem] border border-slate-100">
                           <div className="text-[7px] font-black text-slate-400 uppercase tracking-widest mb-2">Vocal Identity Mapping</div>
                           <div className="text-sm font-bold text-slate-700 break-words">{metadata.vocalIdentity}</div>
                        </div>
                     </div>
                  </div>
               </div>
            ) : (
               <div className="py-20 flex flex-col items-center justify-center text-center space-y-4 opacity-30 grayscale">
                  <div className="text-6xl">🤖</div>
                  <h4 className="text-lg font-black text-slate-400 uppercase tracking-widest">Neural Workspace Empty</h4>
                  <p className="text-xs text-slate-400 max-w-xs font-medium italic">Upload content to initiate vocal fingerprinting and cross-lingual synthesis.</p>
               </div>
            )}
         </div>
      </div>
    </div>
  );
