                           <div className="text-xl font-black text-indigo-600 truncate">{(metadata.confidence * 100).toFixed(0)}%</div>
                        </div>
                        <div className="col-span-2 p-4 md:p-6 bg-slate-50 rounded-[1.5rem] border border-slate-100 overflow-hidden">
