               </div>
            ) : (
               <div className="py-20 flex flex-col items-center justify-center text-center space-y-4 opacity-30 grayscale overflow-hidden">
                  <div className="text-6xl">🤖</div>
                  <h4 className="text-lg font-black text-slate-400 uppercase tracking-widest truncate">Neural Workspace Empty</h4>
                  <p className="text-xs text-slate-400 max-w-xs font-medium italic break-words">Upload content to initiate vocal fingerprinting and cross-lingual synthesis.</p>
               </div>
            )}
         </div>
      </div>
    </div>
  );
};

