import React, { useState, useEffect } from 'react';
import { AppView } from '../types';

interface LayoutProps {
  currentView: AppView;
  setView: (view: AppView) => void;
  children: React.ReactNode;
}

const Layout: React.FC<LayoutProps> = ({ currentView, setView, children }) => {
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    setIsMobileMenuOpen(false);
  }, [currentView]);

  const navItems = [
    { id: AppView.HOME, label: 'Overview', icon: '🏠' },
    { id: AppView.WORKSPACE, label: 'Dubbing Workspace', icon: '🎙️' },
    { id: AppView.ANALYSIS, label: 'Real-Time Analytics', icon: '📊' }
  ];

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans">
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[60] lg:hidden transition-opacity"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      <aside 
        className={`
          fixed inset-y-0 left-0 z-[70] lg:relative lg:flex flex-col shrink-0 transition-all duration-300 ease-in-out border-r border-slate-800 shadow-2xl bg-slate-900 text-white
          ${isCollapsed ? 'lg:w-20' : 'lg:w-72'} 
          ${isMobileMenuOpen ? 'w-72 translate-x-0' : 'w-72 -translate-x-full lg:translate-x-0'}
        `}
      >
        <div className="p-6 h-20 lg:h-24 flex items-center justify-between overflow-hidden shrink-0">
          {(!isCollapsed || isMobileMenuOpen) ? (
            <div className="animate-fadeIn min-w-0">
              <h1 className="text-xl font-black tracking-tighter text-blue-400 flex items-center truncate">
                EmoDub
                <span className="ml-2 px-1.5 py-0.5 bg-blue-500/10 border border-blue-500/20 text-[8px] text-blue-400 rounded uppercase tracking-widest font-black shrink-0">PRO</span>
              </h1>
              <span className="text-[9px] text-slate-500 block font-black mt-1 uppercase tracking-[0.2em] truncate">Neural Engine</span>
            </div>
          ) : (
            <div className="w-full flex justify-center">
              <span className="text-2xl shrink-0">🧬</span>
            </div>
          )}
          <button onClick={() => setIsMobileMenuOpen(false)} className="lg:hidden p-2 text-slate-400 shrink-0">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <nav className="flex-1 px-3 py-4 space-y-2 overflow-y-auto min-w-0">
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setView(item.id)}
              className={`w-full flex items-center px-4 py-4 rounded-[1.25rem] transition-all duration-200 group relative min-w-0 ${
                currentView === item.id 
                  ? 'bg-blue-600 text-white shadow-xl shadow-blue-900/40' 
                  : 'text-slate-500 hover:bg-slate-800/50 hover:text-slate-200'
              }`}
            >
              <span className={`text-xl shrink-0 transition-transform group-hover:scale-110 ${(isCollapsed && !isMobileMenuOpen) ? 'mx-auto' : 'mr-4'}`}>
                {item.icon}
              </span>
              {(!isCollapsed || isMobileMenuOpen) && (
                <span className="text-sm font-black uppercase tracking-tight whitespace-nowrap overflow-hidden truncate">
                  {item.label}
                </span>
              )}
            </button>
          ))}
        </nav>

        <div className="p-6 border-t border-slate-800 shrink-0">
          <div className={`flex items-center ${(isCollapsed && !isMobileMenuOpen) ? 'justify-center' : 'space-x-4'} text-[9px] font-black text-slate-500 uppercase tracking-widest truncate`}>
            <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse shrink-0"></div>
            {(!isCollapsed || isMobileMenuOpen) && <span className="truncate">System: Optimal</span>}
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden relative min-w-0">
        <header className="h-20 bg-white/80 backdrop-blur-md border-b border-slate-200 flex items-center justify-between px-4 md:px-10 shrink-0 z-40">
          <div className="flex items-center space-x-4 md:space-x-6 min-w-0">
            <button 
              onClick={() => {
                if (window.innerWidth < 1024) setIsMobileMenuOpen(true);
                else setIsCollapsed(!isCollapsed);
              }}
              className="p-2 text-slate-500 hover:bg-slate-100 rounded-lg transition-colors shrink-0"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
            <h2 className="text-[10px] md:text-sm font-black text-slate-900 uppercase tracking-[0.1em] md:tracking-[0.2em] italic truncate min-w-0">
              {navItems.find(i => i.id === currentView)?.label}
            </h2>
          </div>
          <div className="flex items-center space-x-3 md:space-x-6 shrink-0 min-w-0">
            <div className="hidden sm:flex flex-col items-end min-w-0">
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest truncate">Researcher</span>
              <span className="text-[10px] text-slate-700 font-black truncate uppercase">N. JOHNSON</span>
            </div>
            <div className="w-9 h-9 rounded-xl overflow-hidden border-2 border-slate-100 shrink-0">
              <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=Neena" className="w-full h-full object-cover" alt="Profile" />
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-10 bg-slate-50/50 min-w-0">
          <div className="max-w-7xl mx-auto w-full min-w-0">
            {children}
          </div>
        </div>
      </main>
    </div>
  );
};

export default Layout;

