import React, { useState, useRef, useEffect } from 'react';
import { LANGUAGES } from '../constants';
import { processDubbingPipeline, generateDubbedVideo, pollOperation, runComparativeAnalysis } from '../services/geminiService';
import { PipelineStep, DubbingMetadata, PipelineStepStatus } from '../types';

const createWavFile = (base64Pcm: string, sampleRate = 24000) => {
  const pcmData = atob(base64Pcm);
  const dataSize = pcmData.length;
  const buffer = new ArrayBuffer(44 + dataSize);
  const view = new DataView(buffer);
  const writeString = (offset: number, string: string) => {
    for (let i = 0; i < string.length; i++) view.setUint8(offset + i, string.charCodeAt(i));
  };
  writeString(0, 'RIFF');
  view.setUint32(4, 36 + dataSize, true);
  writeString(8, 'WAVE');
  writeString(12, 'fmt ');
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true);
  view.setUint16(22, 1, true);
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, sampleRate * 2, true);
  view.setUint16(32, 2, true);
  view.setUint16(34, 16, true);
  writeString(36, 'data');
  view.setUint32(40, dataSize, true);
  const uint8View = new Uint8Array(buffer, 44);
  for (let i = 0; i < dataSize; i++) uint8View[i] = pcmData.charCodeAt(i);
  return new Blob([buffer], { type: 'audio/wav' });
};

// Helper to convert blob to base64
const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = (reader.result as string).split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

const Dashboard: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [filePreviewUrl, setFilePreviewUrl] = useState<string | null>(null);
  const [targetLang, setTargetLang] = useState('es');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isGeneratingVideo, setIsGeneratingVideo] = useState(false);
  const [hasApiKey, setHasApiKey] = useState<boolean | null>(null);
  const [metadata, setMetadata] = useState<DubbingMetadata | null>(null);
  const [dubbedAudioBase64, setDubbedAudioBase64] = useState<string | null>(null);
  const [videoResultUrl, setVideoResultUrl] = useState<string | null>(null);
  const [fidelityReport, setFidelityReport] = useState<any>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const [steps, setSteps] = useState<PipelineStep[]>([
    { id: 'asr', label: 'Vocal Fingerprinting', status: 'pending', detail: 'Analyzing speaker identity...' },
    { id: 'trans', label: 'Semantic Dubbing', status: 'pending', detail: 'Translating with prosody...' },
    { id: 'synth', label: 'Audio Resynthesis', status: 'pending', detail: 'Cloning vocal characteristics...' },
    { id: 'veo', label: 'Lip-Sync Generation', status: 'pending', detail: 'Synthesizing visual frames...' },
    { id: 'analysis', label: 'Worthiness Analysis', status: 'pending', detail: 'Evaluating algorithm fidelity...' },
  ]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const sourceVideoRef = useRef<HTMLVideoElement>(null);
  const outputVideoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    const checkKey = async () => {
      try {
        const selected = await (window as any).aistudio?.hasSelectedApiKey();
        setHasApiKey(!!selected);
      } catch (e) {
        setHasApiKey(false);
      }
    };
    checkKey();
  }, []);

  const handleOpenKeySelector = async () => {
    try {
      await (window as any).aistudio?.openSelectKey();
      setHasApiKey(true);
      setErrorMessage(null);
    } catch (e) {
      console.error("Failed to open key selector", e);
    }
  };

  const updateStep = (id: string, status: PipelineStepStatus, detail?: string) => {
    setSteps(prev => prev.map(s => s.id === id ? { ...s, status, detail: detail || s.detail } : s));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      setFilePreviewUrl(URL.createObjectURL(selectedFile));
      setMetadata(null);
      setFidelityReport(null);
      setVideoResultUrl(null);
      setDubbedAudioBase64(null);
      setErrorMessage(null);
      setSteps(prev => prev.map(s => ({ ...s, status: 'pending', detail: '' })));
    }
  };

  const runPipeline = async () => {
    if (!file) return;
    setIsProcessing(true);
    setErrorMessage(null);
    setSteps(prev => prev.map(s => ({ ...s, status: 'pending', detail: '' })));

    try {
      const reader = new FileReader();
      const base64Promise = new Promise<string>((resolve) => {
        reader.onload = () => resolve(reader.result?.toString().split(',')[1] || '');
      });
      reader.readAsDataURL(file);
      const base64 = await base64Promise;
      const langName = LANGUAGES.find(l => l.code === targetLang)?.name || 'Spanish';

      // Stage 1-3
      updateStep('asr', 'active');
      const { metadata: meta, dubbedAudioBase64: audioData } = await processDubbingPipeline(base64, file.type, langName);
      setMetadata(meta);
      if (audioData) setDubbedAudioBase64(audioData);
      updateStep('asr', 'completed');
      updateStep('trans', 'active');
      // Briefly show trans is active for effect since it's part of the same call
      await new Promise(r => setTimeout(r, 500));
      updateStep('trans', 'completed');
      updateStep('synth', 'completed');

      // Stage 4: Veo
      if (file.type.startsWith('video')) {
        setIsGeneratingVideo(true);
        updateStep('veo', 'active');
        const canvas = document.createElement('canvas');
        canvas.width = sourceVideoRef.current?.videoWidth || 640;
        canvas.height = sourceVideoRef.current?.videoHeight || 360;
        canvas.getContext('2d')?.drawImage(sourceVideoRef.current!, 0, 0);
        const frame = canvas.toDataURL('image/png').split(',')[1];

        try {
          let operation = await generateDubbedVideo(frame, meta.translatedText, meta.emotion, langName);
          while (!operation.done) {
            await new Promise(r => setTimeout(r, 10000));
            operation = await pollOperation(operation);
          }
          const link = operation.response?.generatedVideos?.[0]?.video?.uri;
          if (link) {
            const res = await fetch(`${link}&key=${process.env.API_KEY}`);
            if (!res.ok) throw new Error(`Video fetch failed: ${res.status}`);
            setVideoResultUrl(URL.createObjectURL(await res.blob()));
            updateStep('veo', 'completed');
          }
        } catch (e: any) {
          const errStr = JSON.stringify(e);
          console.error("Veo Error Captured:", errStr);

          const is403 = e.status === 403 || errStr.includes('403') || errStr.includes('PERMISSION_DENIED');
          const isNotFound = errStr.includes('Requested entity was not found');

          if (is403 || isNotFound) {
            setHasApiKey(false); 
            updateStep('veo', 'error', 'Auth Denied');
            setErrorMessage("Access Denied: Veo synthesis requires a PAID Google Cloud API Key.");
          } else {
            updateStep('veo', 'error', 'Interrupted');
            setErrorMessage("Lip-sync generation failed. The system skipped this step.");
          }
        } finally {
          setIsGeneratingVideo(false);
        }
      }

      // Stage 5: Analysis
      if (audioData) {
        updateStep('analysis', 'active');
        const wavBlob = createWavFile(audioData);
        const wavBase64 = await blobToBase64(wavBlob);
        const report = await runComparativeAnalysis(meta, wavBase64, langName);
        setFidelityReport(report);
        updateStep('analysis', 'completed', `Fidelity: ${report.worthinessScore}%`);
      }

    } catch (err: any) {
      const errStr = JSON.stringify(err);
      console.error("Critical Workspace Error:", err);
      if (errStr.includes('403') || errStr.includes('PERMISSION_DENIED') || errStr.includes('Requested entity was not found')) {
        setHasApiKey(false);
        setErrorMessage("Permission Denied: Paid Key Required.");
      }
      setSteps(prev => prev.map(s => s.status === 'active' ? { ...s, status: 'error', detail: 'Workflow Aborted' } : s));
    } finally {
      setIsProcessing(false);
    }
  };

  const completedStepsCount = steps.filter(s => s.status === 'completed').length;
  const progressPercent = (completedStepsCount / steps.length) * 100;

  if (hasApiKey === false) {
    return (
      <div className="flex items-center justify-center min-h-[60vh] p-4 md:p-8 animate-fadeIn">
        <div className="max-w-xl w-full bg-white p-8 md:p-12 rounded-[3.5rem] border border-slate-200 shadow-2xl text-center space-y-10">
          <div className="w-24 h-24 bg-amber-50 rounded-[2.5rem] flex items-center justify-center text-5xl mx-auto shadow-inner border border-amber-100">🔒</div>
          <div className="space-y-6">
            <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tighter leading-none">Access Restricted</h2>
            <p className="text-slate-500 font-medium leading-relaxed px-4">
              {errorMessage || "To enable Veo lip-sync generation and high-fidelity resynthesis, you must select an API key from a Google Cloud project with a PAID billing account."}
            </p>
          </div>
          <button onClick={handleOpenKeySelector} className="w-full py-6 bg-blue-600 hover:bg-blue-700 text-white font-black rounded-[2rem] transition-all shadow-2xl shadow-blue-100 uppercase text-xs tracking-[0.2em] active:scale-95">
            Authenticate Paid Key
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 md:gap-10 animate-fadeIn w-full overflow-hidden">
      {/* Sidebar Timeline */}
      <div className="lg:col-span-1 space-y-6 min-w-0">
        <div className="bg-white p-6 rounded-[2.5rem] border border-slate-200 shadow-sm space-y-6">
           <div className="flex justify-between items-center">
             <h3 className="text-lg font-black text-slate-800 uppercase tracking-tighter">Workspace</h3>
             <button onClick={() => setHasApiKey(false)} className="text-[8px] font-black text-slate-400 hover:text-blue-600 uppercase tracking-widest transition-colors">Reset Auth</button>
           </div>
           <div onClick={() => fileInputRef.current?.click()} className={`border-4 border-dashed rounded-[2rem] p-6 text-center cursor-pointer min-h-[160px] flex flex-col items-center justify-center transition-all ${file ? 'bg-blue-50 border-blue-200' : 'border-slate-100 hover:bg-slate-50'}`}>
              <input type="file" ref={fileInputRef} onChange={handleFileChange} hidden accept="video/*,audio/*" />
              <span className="text-4xl mb-2">{file ? '🎞️' : '📤'}</span>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest break-words w-full px-2 line-clamp-2">{file ? file.name : 'Upload Source'}</p>
           </div>
           <div className="space-y-4">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Localization Target</label>
              <select value={targetLang} onChange={(e) => setTargetLang(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold appearance-none outline-none focus:ring-2 focus:ring-blue-500">
                {LANGUAGES.map(l => <option key={l.code} value={l.code}>{l.name}</option>)}
              </select>
           </div>
           <button onClick={runPipeline} disabled={!file || isProcessing} className={`w-full py-5 rounded-2xl font-black text-xs uppercase tracking-widest transition-all ${!file || isProcessing ? 'bg-slate-100 text-slate-400 cursor-not-allowed' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-xl shadow-blue-100 active:scale-95'}`}>
              {isProcessing ? 'Synthesizing...' : 'Run Neural Pipeline'}
           </button>
        </div>

        {/* Visual Vertical Timeline */}
        <div className="bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800 shadow-2xl relative overflow-hidden">
           <div className="absolute top-0 right-0 w-32 h-32 bg-blue-500/5 blur-[60px] rounded-full pointer-events-none"></div>
           <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-10">Neural Pipeline Flow</h4>
           <div className="relative">
              {/* Connecting line */}
              <div className="absolute left-[9px] top-2 bottom-2 w-0.5 bg-slate-800">
                 <div 
                   className="w-full bg-blue-500 transition-all duration-700 ease-in-out" 
                   style={{ height: `${(completedStepsCount / (steps.length - 1)) * 100}%` }}
                 />
              </div>

              <div className="space-y-10 relative">
                {steps.map((step, idx) => (
                  <div key={step.id} className="flex space-x-6 items-start group">
                     <div className="relative z-10 shrink-0">
                        <div className={`w-5 h-5 rounded-full flex items-center justify-center text-[8px] font-black border transition-all duration-500 ${
                          step.status === 'completed' ? 'bg-green-500 border-green-400 text-white scale-110 shadow-[0_0_15px_rgba(34,197,94,0.4)]' : 
                          step.status === 'active' ? 'bg-blue-500 border-blue-400 text-white animate-pulse shadow-[0_0_20px_rgba(59,130,246,0.5)]' : 
                          step.status === 'error' ? 'bg-red-500 border-red-400 text-white animate-bounce shadow-[0_0_15px_rgba(239,68,68,0.4)]' : 
                          'bg-slate-800 border-slate-700 text-slate-500'
                        }`}>
                           {step.status === 'completed' ? '✓' : ''}
                        </div>
                     </div>
                     <div className="min-w-0 flex-1 -mt-1">
                        <div className={`text-[12px] font-black tracking-tight uppercase transition-colors ${
                          step.status === 'active' ? 'text-blue-400' : 
                          step.status === 'completed' ? 'text-slate-100' : 
                          'text-slate-600'
                        }`}>
                          {step.label}
