    const errStr = JSON.stringify(err);
    return (
      err.status === 403 || 
      err?.error?.code === 403 || 
      err?.name === "ApiError" && err.status === 403 ||
      errStr.includes('PERMISSION_DENIED') || 
      errStr.includes('403') ||
      errStr.includes('Requested entity was not found')
