import { PipelineStep, DubbingMetadata, PipelineStepStatus } from '../types';

const createWavFile = (base64Pcm: string, sampleRate = 24000) => {
  const pcmData = atob(base64Pcm);
  const dataSize = pcmData.length;
  const buffer = new ArrayBuffer(44 + dataSize);
  const view = new DataView(buffer);
  const writeString = (offset: number, string: string) => {
    for (let i = 0; i < string.length; i++) view.setUint8(offset + i, string.charCodeAt(i));
  };
  writeString(0, 'RIFF');
  view.setUint32(4, 36 + dataSize, true);
  writeString(8, 'WAVE');
  writeString(12, 'fmt ');
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true);
  view.setUint16(22, 1, true);
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, sampleRate * 2, true);
  view.setUint16(32, 2, true);
  view.setUint16(34, 16, true);
  writeString(36, 'data');
  view.setUint32(40, dataSize, true);
  const uint8View = new Uint8Array(buffer, 44);
  for (let i = 0; i < dataSize; i++) uint8View[i] = pcmData.charCodeAt(i);
  return new Blob([buffer], { type: 'audio/wav' });
};

const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      resolve(result.split(',')[1]);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

const Dashboard: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [filePreviewUrl, setFilePreviewUrl] = useState<string | null>(null);
  const [targetLang, setTargetLang] = useState('es');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isGeneratingVideo, setIsGeneratingVideo] = useState(false);
  const [hasApiKey, setHasApiKey] = useState<boolean | null>(null);
  const [metadata, setMetadata] = useState<DubbingMetadata | null>(null);
  const [dubbedAudioBase64, setDubbedAudioBase64] = useState<string | null>(null);
  const [videoResultUrl, setVideoResultUrl] = useState<string | null>(null);
  const [fidelityReport, setFidelityReport] = useState<any>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const [steps, setSteps] = useState<PipelineStep[]>([
    { id: 'asr', label: 'Vocal Fingerprinting', status: 'pending', detail: 'Analyzing speaker identity...' },
    { id: 'trans', label: 'Semantic Dubbing', status: 'pending', detail: 'Translating with prosody...' },
    { id: 'synth', label: 'Audio Resynthesis', status: 'pending', detail: 'Cloning vocal characteristics...' },
    { id: 'veo', label: 'Lip-Sync Generation', status: 'pending', detail: 'Synthesizing visual frames...' },
    { id: 'analysis', label: 'Worthiness Analysis', status: 'pending', detail: 'Evaluating algorithm fidelity...' },
  ]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const sourceVideoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    const checkKey = async () => {
      try {
        const selected = await (window as any).aistudio?.hasSelectedApiKey();
        setHasApiKey(!!selected);
      } catch (e) {
        setHasApiKey(false);
      }
    };
    checkKey();
  }, []);

  const handleOpenKeySelector = async () => {
    try {
      await (window as any).aistudio?.openSelectKey();
      setHasApiKey(true);
      setErrorMessage(null);
    } catch (e) {
      console.error("Auth Dialog Error:", e);
    }
  };

  const isAuthError = (err: any) => {
    const errStr = JSON.stringify(err);
    return (
      err.status === 403 || 
      err?.error?.code === 403 || 
      errStr.includes('403') || 
      errStr.includes('PERMISSION_DENIED') || 
      errStr.includes('entity was not found')
    );
  };

  const updateStep = (id: string, status: PipelineStepStatus, detail?: string) => {
    setSteps(prev => prev.map(s => s.id === id ? { ...s, status, detail: detail || s.detail } : s));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      setFilePreviewUrl(URL.createObjectURL(selectedFile));
      setMetadata(null);
      setFidelityReport(null);
      setVideoResultUrl(null);
      setDubbedAudioBase64(null);
      setErrorMessage(null);
      setSteps(prev => prev.map(s => ({ ...s, status: 'pending', detail: '' })));
    }
  };

  const runPipeline = async () => {
    if (!file) return;
    setIsProcessing(true);
    setErrorMessage(null);
    setSteps(prev => prev.map(s => ({ ...s, status: 'pending', detail: '' })));

    try {
      const base64 = await blobToBase64(file);
      const langName = LANGUAGES.find(l => l.code === targetLang)?.name || 'Spanish';

      updateStep('asr', 'active');
      const { metadata: meta, dubbedAudioBase64: audioData } = await processDubbingPipeline(base64, file.type, langName);
      setMetadata(meta);
      setDubbedAudioBase64(audioData || null);

      updateStep('asr', 'completed', `Detected: ${meta.gender}`);
      updateStep('trans', 'completed', `Target: ${langName}`);
      updateStep('synth', 'completed', `Emotion: ${meta.emotion}`);

      if (file.type.startsWith('video')) {
        setIsGeneratingVideo(true);
        updateStep('veo', 'active');
        const canvas = document.createElement('canvas');
        canvas.width = sourceVideoRef.current?.videoWidth || 640;
        canvas.height = sourceVideoRef.current?.videoHeight || 360;
        canvas.getContext('2d')?.drawImage(sourceVideoRef.current!, 0, 0);
        const frame = canvas.toDataURL('image/png').split(',')[1];

        try {
          let operation = await generateDubbedVideo(frame, meta.translatedText, meta.emotion, langName);
          while (!operation.done) {
            await new Promise(r => setTimeout(r, 10000));
            operation = await pollOperation(operation);
          }
          const link = operation.response?.generatedVideos?.[0]?.video?.uri;
          if (link) {
            const res = await fetch(`${link}&key=${process.env.API_KEY}`);
            if (!res.ok) throw res;
            setVideoResultUrl(URL.createObjectURL(await res.blob()));
            updateStep('veo', 'completed');
          }
        } catch (e: any) {
          if (isAuthError(e)) {
            setHasApiKey(false);
            setErrorMessage("Paid Tier Required: Veo video generation is restricted to projects with billing enabled.");
            updateStep('veo', 'error', 'Auth Reset');
            throw e;
          } else {
            updateStep('veo', 'error', 'Generation Failed');
          }
        } finally {
          setIsGeneratingVideo(false);
        }
      }

      if (audioData) {
        updateStep('analysis', 'active');
        const wavBase64 = await blobToBase64(createWavFile(audioData));
        const report = await runComparativeAnalysis(meta, wavBase64, langName);
        setFidelityReport(report);
        updateStep('analysis', 'completed', `${report.worthinessScore}% Fidelity`);
      }
    } catch (err: any) {
      console.error("Pipeline Sync Error:", err);
      if (isAuthError(err)) {
        setHasApiKey(false);
        setErrorMessage("Permission Denied: Please use a Paid Tier API Key from a valid project.");
      }
      setSteps(prev => prev.map(s => s.status === 'active' ? { ...s, status: 'error', detail: 'Workflow Aborted' } : s));
    } finally {
      setIsProcessing(false);
    }
  };

  const progressPercent = (steps.filter(s => s.status === 'completed').length / steps.length) * 100;

  if (hasApiKey === false) {
    return (
      <div className="flex items-center justify-center min-h-[60vh] p-8 animate-fadeIn">
        <div className="max-w-xl w-full bg-white p-12 rounded-[3.5rem] border border-slate-200 shadow-2xl text-center space-y-10">
          <div className="text-6xl">🔒</div>
          <div className="space-y-4">
            <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tighter">Paid Authentication Required</h2>
            <p className="text-slate-500 font-medium leading-relaxed">
              {errorMessage || "Generative video and high-fidelity dubbing (Veo) require a Paid Tier API Key from a Google Cloud project with active billing."}
            </p>
            <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 text-[10px] text-slate-400 font-bold uppercase tracking-widest text-center">
              Reference: <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noopener noreferrer" className="text-blue-600 underline">GCP Billing Docs</a>
            </div>
          </div>
          <button onClick={handleOpenKeySelector} className="w-full py-6 bg-blue-600 hover:bg-blue-700 text-white font-black rounded-[2rem] transition-all shadow-2xl uppercase text-xs tracking-[0.2em] active:scale-95">
            Authenticate Paid Key
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-10 animate-fadeIn">
      <div className="lg:col-span-1 space-y-6">
        <div className="bg-white p-6 rounded-[2.5rem] border border-slate-200 shadow-sm space-y-6">
           <div className="flex justify-between items-center">
             <h3 className="text-lg font-black text-slate-800 uppercase tracking-tighter">Workflow</h3>
             <button onClick={() => setHasApiKey(false)} className="text-[8px] font-black text-slate-400 hover:text-blue-600 uppercase tracking-widest">Reset API</button>
           </div>
           <div onClick={() => fileInputRef.current?.click()} className={`border-4 border-dashed rounded-[2rem] p-6 text-center cursor-pointer min-h-[160px] flex flex-col items-center justify-center transition-all ${file ? 'bg-blue-50 border-blue-200' : 'border-slate-100 hover:bg-slate-50'}`}>
              <input type="file" ref={fileInputRef} onChange={handleFileChange} hidden accept="video/*,audio/*" />
              <span className="text-4xl mb-2">{file ? '🎞️' : '📤'}</span>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest line-clamp-1">{file ? file.name : 'Upload Performance'}</p>
           </div>
           <div className="space-y-4">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Neural Target Language</label>
              <select value={targetLang} onChange={(e) => setTargetLang(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold outline-none focus:ring-2 focus:ring-blue-500">
                {LANGUAGES.map(l => <option key={l.code} value={l.code}>{l.name}</option>)}
              </select>
           </div>
           <button onClick={runPipeline} disabled={!file || isProcessing} className={`w-full py-5 rounded-2xl font-black text-xs uppercase tracking-widest transition-all ${!file || isProcessing ? 'bg-slate-100 text-slate-400 cursor-not-allowed' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-xl active:scale-95'}`}>
              {isProcessing ? 'Synthesizing...' : 'Initialize Dubbing'}
           </button>
        </div>

        <div className="bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800 shadow-2xl">
           <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-10">Neural Timeline</h4>
           <div className="space-y-10 relative">
              <div className="absolute left-[9px] top-2 bottom-2 w-0.5 bg-slate-800" />
              {steps.map((step) => (
                <div key={step.id} className="flex space-x-6 items-start">
                   <div className={`w-5 h-5 rounded-full z-10 flex items-center justify-center text-[8px] font-black border transition-all ${
                     step.status === 'completed' ? 'bg-green-500 border-green-400 text-white' : 
                     step.status === 'active' ? 'bg-blue-500 border-blue-400 text-white animate-pulse' : 
                     step.status === 'error' ? 'bg-red-500 border-red-400 text-white' : 
                     'bg-slate-800 border-slate-700 text-slate-500'
                   }`}>
                      {step.status === 'completed' ? '✓' : ''}
                   </div>
                   <div className="min-w-0 flex-1 -mt-1">
                      <div className={`text-[12px] font-black uppercase ${step.status === 'active' ? 'text-blue-400' : 'text-slate-100'}`}>{step.label}</div>
                      <div className="text-[9px] font-bold mt-1 text-slate-700 uppercase tracking-widest truncate">{step.detail || 'Queued...'}</div>
                   </div>
                </div>
              ))}
           </div>
        </div>
      </div>

      <div className="lg:col-span-3 space-y-8">
         <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="bg-black rounded-[3rem] overflow-hidden aspect-video relative shadow-2xl">
               <video ref={sourceVideoRef} src={filePreviewUrl || ''} className="w-full h-full object-cover opacity-80" muted playsInline />
               <div className="absolute top-6 left-6 px-3 py-1 bg-white/10 backdrop-blur rounded-full text-[10px] font-black text-white uppercase tracking-widest border border-white/20">Source Feed</div>
            </div>
            <div className="bg-slate-900 rounded-[3rem] overflow-hidden aspect-video relative shadow-2xl border border-slate-800">
               {videoResultUrl ? (
                  <video src={videoResultUrl} className="w-full h-full object-cover" controls />
               ) : (
                  <div className="w-full h-full flex flex-col items-center justify-center text-center p-12">
                     {isGeneratingVideo ? (
                        <div className="space-y-6">
                           <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto"></div>
                           <h4 className="text-white font-black uppercase text-[10px] tracking-widest animate-pulse">Veo Generative Resynthesis...</h4>
                        </div>
                     ) : (
                        <div className="opacity-20 space-y-4">
                           <div className="text-7xl">🧬</div>
                           <h4 className="text-white font-black uppercase text-[10px] tracking-widest">Awaiting Frame Sync</h4>
                        </div>
                     )}
                  </div>
               )}
               <div className="absolute top-6 right-6 px-3 py-1 bg-blue-600 rounded-full text-[10px] font-black text-white uppercase tracking-widest shadow-lg">Master Composite</div>
            </div>
         </div>

         {metadata && (
            <div className="bg-white p-12 rounded-[3.5rem] border border-slate-200 shadow-xl space-y-12 animate-fadeIn">
               <div className="flex justify-between items-center pb-10 border-b border-slate-100">
                  <h2 className="text-4xl font-black text-slate-900 tracking-tighter">Dubbing Workspace</h2>
                  <div className="flex gap-4">
                     {dubbedAudioBase64 && (
                        <button onClick={() => { const blob = createWavFile(dubbedAudioBase64); const link = document.createElement('a'); link.href = URL.createObjectURL(blob); link.download = 'vocal_stem.wav'; link.click(); }} className="px-10 py-5 bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest rounded-2xl shadow-2xl active:scale-95">Export Stem</button>
                     )}
                     {videoResultUrl && (
                        <button onClick={() => { const link = document.createElement('a'); link.href = videoResultUrl; link.download = 'master_performance.mp4'; link.click(); }} className="px-10 py-5 bg-blue-600 text-white font-black text-[10px] uppercase tracking-widest rounded-2xl shadow-blue-100 shadow-2xl active:scale-95">Export Master</button>
                     )}
                  </div>
               </div>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                  <div className="space-y-6">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Neural Semantic Logic</label>
                     <div className="p-10 bg-slate-50 rounded-[3rem] border border-slate-100 italic text-2xl text-slate-800 leading-relaxed font-serif shadow-inner">
                        "{metadata.translatedText}"
                     </div>
                  </div>
                  <div className="grid grid-cols-2 gap-6">
                     <div className="p-8 bg-slate-50 rounded-[2.5rem] text-center border border-slate-100">
                        <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-4">Acoustic Identity</div>
                        <div className="text-3xl font-black text-blue-600 uppercase tracking-tighter">{metadata.gender}</div>
                     </div>
                     <div className="p-8 bg-slate-50 rounded-[2.5rem] text-center border border-slate-100">
                        <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-4">Emotive State</div>
