import React, { useState, useRef } from 'react';
import { processDubbingPipeline } from '../services/geminiService';
import { DubbingMetadata } from '../types';

const Dashboard: React.FC = () => {
  const [audioFile, setAudioFile] = useState<File | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [targetLang, setTargetLang] = useState('Tamil');
  const [isCloningEnabled, setIsCloningEnabled] = useState(true);
  const [isHowToOpen, setIsHowToOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  // Results state
  const [resultMetadata, setResultMetadata] = useState<DubbingMetadata | null>(null);
  const [dubbedAudioUrl, setDubbedAudioUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const audioInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  // Helper: Convert File to Base64
  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = (error) => reject(error);
    });
  };

  // Helper: Add WAV Header to raw PCM data (Gemini TTS returns 24kHz mono PCM)
  const createWavUrl = (base64Pcm: string): string => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }

    const sampleRate = 24000;
    const numChannels = 1;
    const bitsPerSample = 16;
    const header = new ArrayBuffer(44);
    const view = new DataView(header);

    const writeString = (view: DataView, offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) {
        view.setUint8(offset + i, string.charCodeAt(i));
      }
    };

    writeString(view, 0, 'RIFF');
    view.setUint32(4, 32 + bytes.length, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true); // PCM format
    view.setUint16(22, numChannels, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * numChannels * (bitsPerSample / 8), true);
    view.setUint16(32, numChannels * (bitsPerSample / 8), true);
    view.setUint16(34, bitsPerSample, true);
    writeString(view, 36, 'data');
    view.setUint32(40, bytes.length, true);

    const blob = new Blob([header, bytes], { type: 'audio/wav' });
    return URL.createObjectURL(blob);
  };

  const runPipeline = async () => {
    const file = audioFile || videoFile;
    if (!file) return;

    setIsProcessing(true);
    setError(null);
    setResultMetadata(null);
    setDubbedAudioUrl(null);

    try {
      const base64Data = await fileToBase64(file);
      const mimeType = file.type;

      const response = await processDubbingPipeline(base64Data, mimeType, targetLang);

      if (response.dubbedAudioBase64) {
        const audioUrl = createWavUrl(response.dubbedAudioBase64);
        setDubbedAudioUrl(audioUrl);
      }

      setResultMetadata(response.metadata);
    } catch (err: any) {
      console.error("Pipeline Error:", err);
      setError("The neural engine encountered an error analyzing this file. Please ensure the audio is clear and under 200MB.");
    } finally {
      setIsProcessing(false);
    }
  };

  const UploadZone = ({ title, sub, refObj, file, setFile, accept }: any) => (
    <div className="space-y-4">
      <div className="flex items-center gap-3 text-[11px] font-black text-slate-500 uppercase tracking-[0.2em]">
