            <div className="text-[11px] text-slate-500 font-semibold tracking-wide mt-1">{sub}</div>
          </div>
        </div>
        <button className="bg-[#21262d] text-white text-[12px] font-black uppercase tracking-widest px-6 py-3 rounded-xl border border-slate-700 hover:bg-[#30363d] transition-colors shrink-0 hidden sm:block">
